import type { AriaLabelingProps, AriaDisabledProps } from './a11y-props.js';
import type { DOMProps } from './dom.js';
import type { FormControlStateProps } from './form-control-state.js';
/**
 * The base props of a form control.
 * @public
 */
export interface FormControlBaseProps<TOnChange extends (...args: any[]) => void = (...args: any[]) => void> extends DOMProps, AriaLabelingProps, AriaDisabledProps, FormControlStateProps {
    /**
     * Whether the control is disabled.
     * If true, the control cannot be interacted with and is not submitted in a form.
     * @defaultValue false
     */
    disabled?: boolean;
    /**
     * Whether the control is required.
     * @defaultValue false
     */
    required?: boolean;
    /**
     * Whether the control is readonly.
     * If true, the control cannot be interacted with, but is submitted in a form.
     * @defaultValue false
     */
    readOnly?: boolean;
    /**
     * The name used for the form control, used as identifier when submitting it in a form.
     * @defaultValue undefined
     */
    name?: string;
    /**
     * Callback triggered when the form control value changes.
     */
    onChange?: TOnChange;
}
/**
 * Props of a controlled form control.
 * @public
 */
export interface FormControlControlledProps<TValue> {
    /** The value of the form control. */
    value?: TValue;
    /** The default value of the form control. */
    defaultValue?: never;
}
/**
 * Props of an uncontrolled form control.
 * @public
 */
export interface FormControlUncontrolledProps<TValue> {
    /** The value of the form control. */
    value?: never;
    /** The default value of the form control. */
    defaultValue?: TValue;
}
/**
 * Base type for form controls that can be either controlled or uncontrolled.
 * The generic accepts two parameters:
 * @param TValue - Type of the value / defaultValue.
 * @param TOnChange - Type of the 'onChange' callback.
 * @public
 */
export type FormControlProps<TValue, TOnChange extends (...args: any[]) => void = (...args: any[]) => void> = FormControlBaseProps<TOnChange> & (FormControlControlledProps<TValue> | FormControlUncontrolledProps<TValue>);
